\documentclass{standalone}
\usepackage{tikz}
\usepackage{xcolor}

\begin{document}

\begin{tikzpicture}[scale=1.5]
    % Define rectangle dimensions
    \def\rectheight{4}
    \def\rectwidth{10}

    % Draw the original rectangle
    \draw[thick] (0,0) rectangle (\rectwidth,\rectheight);

    % Draw vertical lines for partitions
    \foreach \n in {1,...,4} {
        \draw[thin, gray] (\rectwidth/2^\n,0) -- (\rectwidth/2^\n,\rectheight);
    }

    % Draw the original diagonal (n=0)
    \definecolor{diagcolor0}{rgb}{0.1,0.1,0.8}
    \draw[thick, diagcolor0] (0,0) -- (\rectwidth,\rectheight);
    \node[diagcolor0, font=\small] at (\rectwidth-0.7, \rectheight-0.3) {$n=0$};

    % Draw the zigzag patterns for n=1,2,3,4
    \foreach \n in {1,...,4} {
        % Define a unique color for each n
        \definecolor{diagcolor\n}{rgb}{0.1,0.8-\n*0.15,0.1+\n*0.15}

        % For each n, draw 2^n triangles
        \foreach \m in {0,...,\numexpr2^\n-1} {
            % Calculate the starting x-coordinate for this triangle
            \pgfmathsetmacro{\startx}{\m*\rectwidth/2^\n}
            \pgfmathsetmacro{\endx}{(\m+1)*\rectwidth/2^\n}

            % Draw the upward diagonal
            \draw[thick, diagcolor\n] (\startx,0) -- ({\startx+(\endx-\startx)/2},\rectheight);

            % Draw the downward diagonal
            \draw[thick, diagcolor\n] ({\startx+(\endx-\startx)/2},\rectheight) -- (\endx,0);
        }

        % Add a label for each set of triangles
        \node[diagcolor\n, font=\small] at (\rectwidth-0.7, \rectheight-0.3-\n*0.3) {$n=\n$};
    }

    % Add a note
    \node[below] at (\rectwidth/2,-0.5) {Einstein-like "bouncing light" triangles for n=0,1,2,3,4};

\end{tikzpicture}

\end{document}

